INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 100211, 0, 5012, 1, 11, 10, 5012018, "うん、いい感じに描けたね！\n……でもこの絵って、ずっと\nランドソルに残るんだよね？\nそ、それはちょっと恥ずかしいかも……", 0.5);
