INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 101311, 0, 14112, 1, 11, 10, 14112025, "やった！　これにて完成でござるよ～！\nう～ん、色使いといい、タッチといい、\n今度も素晴らしい出来栄えですな～！", 0.5);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0, "", 14112, "", 91, "", 14112026, "", "");
