INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 100911, 0, 14712, 1, 11, 10, 14712026, "シグルドー！　見てくれ見てくれ！\n今回の絵は、歴史に残る最高傑作……！\n貴様には、その目撃者になる\n栄誉を授けよう！", 0.5);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0, "", 14712, "", 91, "", 14712027, "", "");
