INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 101311, 0, 14712, 1, 11, 10, 14712031, "さすがだね、アンナたそ！\nけど私も負けないよ～！\n芸術の神が舞い降りたかのような\nこの完成度、ぜひご照覧あれ～！", 0.5);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0, "", 14712, "", 91, "", 14712032, "", "");
