INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 106811, 0, 16112, 1, 11, 10, 16112018, "ふぅ……たまにはこうして\n童心に帰って一心に絵を描く\nっていうのもいいものだねぇ……", 0.5);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0, "", 16112, "", 91, "", 16112019, "", "");
