INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 105111, 0.2, 16612, "", 3, 1, 16612039, "wac_talk_surprise_loop_shy", "");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "vo_wac_220730", "", 16612, 0, 21, 0, 16612040, "vo_wac_220730_003", "");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 105111, 0, 16612, 1, 11, 10, 16612041, "まったくもう……\nみんなして絵の具まみれじゃない。\nって、あら？　この赤いのは……", 0.5);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0, "", 16612, "", 91, "", 16612042, "", "");
