INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 102811, 0, 23212, 1, 11, 10, 23212022, "ふぅ、これでできあがりね。\nみんなもすごく上手に描けてるし、\nよく頑張ったわね♪", 0.5);
