INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 109411, 0, 26232, 1, 11, 10, 26232018, "……ええと、アン。\n絵は、こんな感じでいいのかな……？\nやっぱりアンがやった方が……", 0.5);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0, "", 26232, "", 91, "", 26232019, "", "");
