INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "vo_wac_221103", "", 26232, 0, 21, 0, 26232022, "vo_wac_221103_201", "");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 109211, 0, 26232, 1, 11, 10, 26232023, "そんなことない！　バッチリだよ！\nやっぱりグレアは天才かも！\nアートの申し子で間違いない！\nルゥもそう思うでしょ！", 0.5);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0, "", 26232, "", 91, "", 26232024, "", "");
