INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "vo_wac_221125", "", 28412, 0, 21, 0, 28412036, "vo_wac_221125_003", "");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 104711, 0, 28412, 1, 11, 10, 28412037, "クリスちゃんは相変わらずだね。\nでも、描き直したおかげで\nさらに良い絵になったと思うよ。\n私も鎧に絵の具がはねなくて一安心だ。", 0.5);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0, "", 28412, "", 91, "", 28412038, "", "");
