INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 107111, 0, 35812, 1, 11, 10, 35812022, "むっ……おい、マツリちゃん。\nしっぽの先がペンキで汚れているぞ。\nどれ、ワタシが丁寧に拭ってやろう♪", 0.5);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0, "", 35812, "", 91, "", 35812023, "", "");
