INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "vo_wac_230218", "", 36912, 0, 21, 0, 36912026, "vo_wac_230218_001", "");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 100311, 0, 36912, 1, 11, 10, 36912027, "そう言ってもらえてなによりだよ。\n今日、こうして壁に描かれた絵も、\nきっと素敵な思い出になる。", 0.5);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0, "", 36912, "", 91, "", 36912028, "", "");
