INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 0, 105111, 0, 38612, 1, 11, 10, 38612026, "ふぅ、これでいいかしら？\n普段もカルテにスケッチを描く機会は\nあるけれど、絵筆を使ってしっかりと\n描くのはなかなか大変ね……", 0.5);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0, "", 38612, "", 91, "", 38612027, "", "");
